import sys

class Solution:
    def searchMatrix(self, matrix: list[list[int]], target: int) -> bool:
        if not matrix or not matrix[0]:
            return False
        m, n = len(matrix), len(matrix[0])
        left, right = 0, m * n - 1
        while left <= right:
            mid = (left + right) // 2
            i, j = divmod(mid, n)
            val = matrix[i][j]
            if val == target:
                return True
            elif val < target:
                left = mid + 1
            else:
                right = mid - 1
        return False

if __name__ == '__main__':
    it = iter(sys.stdin.read().split())
    try:
        m = int(next(it))
        n = int(next(it))
    except StopIteration:
